import{_ as r,C as o,c as n,o as a,a3 as i,b as E,w as t,a as s,G as h,a4 as u}from"./chunks/framework.CTM16EAR.js";const f=JSON.parse('{"title":"第二阶段：应对打断","description":"","frontmatter":{},"headers":[],"relativePath":"guide/pomodoro-technique/02-handle-interruptions.md","filePath":"guide/pomodoro-technique/02-handle-interruptions.md","lastUpdated":1778035726000}'),A={name:"guide/pomodoro-technique/02-handle-interruptions.md"};function B(d,l,p,c,q,m){const e=o("Mermaid");return a(),n("div",null,[l[1]||(l[1]=i('<h1 id="第二阶段-应对打断" tabindex="-1">第二阶段：应对打断 <a class="header-anchor" href="#第二阶段-应对打断" aria-label="Permalink to &quot;第二阶段：应对打断&quot;">​</a></h1><p><strong>目标</strong>：减少打断对专注的影响，学会记录和处理干扰。</p><blockquote><p>记录入口与控件名称以 <a href="./../reference/task.html">任务追踪</a>、<a href="./../appendix/buttons.html">附录：按钮一览</a> 为准。</p></blockquote><hr><h2 id="打断的类型" tabindex="-1">打断的类型 <a class="header-anchor" href="#打断的类型" aria-label="Permalink to &quot;打断的类型&quot;">​</a></h2><p>番茄工作法把打断分为两类：</p><h3 id="内部打断-internal-interruption" tabindex="-1">内部打断（Internal Interruption） <a class="header-anchor" href="#内部打断-internal-interruption" aria-label="Permalink to &quot;内部打断（Internal Interruption）&quot;">​</a></h3><p><strong>特征</strong>：你自己走神的瞬间</p><ul><li>突然想到&quot;要买牛奶&quot;</li><li>好奇某个无关紧要的问题</li><li>想去查个不紧急的信息</li></ul><p><strong>本质</strong>：大脑在逃避当前的困难任务</p><h3 id="外部打断-external-interruption" tabindex="-1">外部打断（External Interruption） <a class="header-anchor" href="#外部打断-external-interruption" aria-label="Permalink to &quot;外部打断（External Interruption）&quot;">​</a></h3><p><strong>特征</strong>：来自外界的干扰</p><ul><li>同事来问问题</li><li>收到消息通知</li><li>有人敲门</li><li>电话响起</li></ul><hr><h2 id="pomotention-的打断记录" tabindex="-1">Pomotention 的打断记录 <a class="header-anchor" href="#pomotention-的打断记录" aria-label="Permalink to &quot;Pomotention 的打断记录&quot;">​</a></h2><p>在番茄计时过程中，按界面提示打开记录流程（见 <a href="./../reference/timer.html">番茄时钟</a>），其中包含打断记录功能。</p><h3 id="如何记录打断" tabindex="-1">如何记录打断 <a class="header-anchor" href="#如何记录打断" aria-label="Permalink to &quot;如何记录打断&quot;">​</a></h3><ol><li><p><strong>计时过程中被打断</strong></p><ul><li>不要停止计时器</li><li>快速在便签/纸上记下打断内容</li><li>若在软件内记录，按番茄时钟 / 任务追踪相关控件操作（见 reference）</li></ul></li><li><p><strong>记录内容</strong></p><ul><li>打断类型：内部 / 外部</li><li>打断原因：简要描述（如&quot;想买牛奶&quot;、&quot;同事问问题&quot;）</li><li>是否需要处理：现在 / 稍后</li></ul></li><li><p><strong>回到任务</strong></p><ul><li>记录完立即回到原任务</li><li>不要顺着打断内容走</li></ul></li></ol><hr><h2 id="打断处理决策流程" tabindex="-1">打断处理决策流程 <a class="header-anchor" href="#打断处理决策流程" aria-label="Permalink to &quot;打断处理决策流程&quot;">​</a></h2>',20)),(a(),E(u,null,{default:t(()=>[h(e,{id:"mermaid-149",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E7%95%AA%E8%8C%84%E8%BF%9B%E8%A1%8C%E4%B8%AD%5D%20--%3E%20B%7B%E5%87%BA%E7%8E%B0%E6%89%93%E6%96%AD%7D%0A%20%20%20%20B%20--%3E%7C%E5%86%85%E9%83%A8%E8%B5%B0%E7%A5%9E%7C%20C%5B%E5%BF%AB%E9%80%9F%E8%AE%B0%E4%B8%8B%E5%86%85%E5%AE%B9%5D%0A%20%20%20%20B%20--%3E%7C%E5%A4%96%E9%83%A8%E5%B9%B2%E6%89%B0%7C%20D%7B%E8%83%BD%E5%90%A6%E6%8E%A8%E8%BF%9F%3F%7D%0A%20%20%20%20%0A%20%20%20%20D%20--%3E%7C%E8%83%BD%7C%20E%5B%E7%A4%BC%E8%B2%8C%E8%AF%B4%E6%98%8E%E7%A8%8D%E5%90%8E%E5%A4%84%E7%90%86%5D%0A%20%20%20%20D%20--%3E%7C%E4%B8%8D%E8%83%BD%7C%20F%5B%E4%B8%AD%E6%96%AD%E7%95%AA%E8%8C%84%5D%0A%20%20%20%20%0A%20%20%20%20C%20--%3E%20G%5B%E7%AB%8B%E5%8D%B3%E5%9B%9E%E5%88%B0%E4%BB%BB%E5%8A%A1%5D%0A%20%20%20%20E%20--%3E%20G%0A%20%20%20%20%0A%20%20%20%20F%20--%3E%20H%5B%E8%AE%B0%E5%BD%95%E4%B8%AD%E6%96%AD%E5%8E%9F%E5%9B%A0%5D%0A%20%20%20%20H%20--%3E%20I%5B%E5%A4%84%E7%90%86%E7%B4%A7%E6%80%A5%E4%BA%8B%E5%8A%A1%5D%0A%20%20%20%20I%20--%3E%20J%5B%E4%BC%91%E6%81%AF%E6%88%96%E7%9B%B4%E6%8E%A5%E5%BC%80%E5%A7%8B%E6%96%B0%E7%95%AA%E8%8C%84%5D%0A%20%20%20%20%0A%20%20%20%20G%20--%3E%20K%5B%E7%BB%A7%E7%BB%AD%E5%BD%93%E5%89%8D%E7%95%AA%E8%8C%84%5D%0A%20%20%20%20%0A%20%20%20%20K%20--%3E%20L%5B%E7%95%AA%E8%8C%84%E5%AE%8C%E6%88%90%5D%0A%20%20%20%20I%20--%3E%20M%5B%E5%9C%A8%E4%BB%BB%E5%8A%A1%E8%BF%BD%E8%B8%AA%E4%B8%AD%3Cbr%2F%3E%E6%A0%87%E8%AE%B0%E4%B8%AD%E6%96%AD%E7%95%AA%E8%8C%84%5D%0A%20%20%20%20L%20--%3E%20N%5B%E8%AE%B0%E5%BD%95%E5%AE%8C%E6%88%90%E6%83%85%E5%86%B5%5D%0A%20%20%20%20%0A%20%20%20%20style%20F%20fill%3A%23ff9999%0A%20%20%20%20style%20G%20fill%3A%2399ff99%0A%20%20%20%20style%20K%20fill%3A%2399ccff%0A"})]),fallback:t(()=>l[0]||(l[0]=[s(" Loading... ")])),_:1})),l[2]||(l[2]=i('<hr><h2 id="保护番茄的策略" tabindex="-1">保护番茄的策略 <a class="header-anchor" href="#保护番茄的策略" aria-label="Permalink to &quot;保护番茄的策略&quot;">​</a></h2><h3 id="减少内部打断" tabindex="-1">减少内部打断 <a class="header-anchor" href="#减少内部打断" aria-label="Permalink to &quot;减少内部打断&quot;">​</a></h3><ol><li><strong>接受走神</strong>：走神是正常的，关键是发现后马上回来</li><li><strong>快速记下</strong>：用便签纸或软件的快速记录，不要让想法占用大脑内存</li><li><strong>CBT 书写模板</strong>：Pomotention 内置的书写模板可以帮助你处理导致走神的焦虑想法</li></ol><h3 id="减少外部打断" tabindex="-1">减少外部打断 <a class="header-anchor" href="#减少外部打断" aria-label="Permalink to &quot;减少外部打断&quot;">​</a></h3><ol><li><p><strong>物理隔离</strong></p><ul><li>关闭通知</li><li>戴耳机（即使不放音乐）</li><li>在门口/座位放&quot;番茄中，请勿打扰&quot;标识</li></ul></li><li><p><strong>沟通预期</strong></p><ul><li>告诉同事你在用番茄工作法</li><li>约定&quot;紧急&quot;的定义</li><li>非紧急事项请对方留言或稍后</li></ul></li><li><p><strong>快速处理</strong></p><ul><li>如果必须打断，记录原因</li><li>事后分析这类打断是否可以预防</li></ul></li></ol><hr><h2 id="打断数据分析" tabindex="-1">打断数据分析 <a class="header-anchor" href="#打断数据分析" aria-label="Permalink to &quot;打断数据分析&quot;">​</a></h2><h3 id="在任务追踪中查看" tabindex="-1">在任务追踪中查看 <a class="header-anchor" href="#在任务追踪中查看" aria-label="Permalink to &quot;在任务追踪中查看&quot;">​</a></h3><p>完成番茄后，在任务追踪与相关统计入口可以查看：</p><ul><li>本次番茄的打断次数</li><li>打断类型分布</li><li>最常出现的打断原因</li></ul><h3 id="什么时候打断最多" tabindex="-1">什么时候打断最多？ <a class="header-anchor" href="#什么时候打断最多" aria-label="Permalink to &quot;什么时候打断最多？&quot;">​</a></h3><p>通过记录你会发现规律：</p><ul><li>上午还是下午？</li><li>什么类型的任务最容易被打断？</li><li>哪些打断是可以预防的？</li></ul><h3 id="调整策略" tabindex="-1">调整策略 <a class="header-anchor" href="#调整策略" aria-label="Permalink to &quot;调整策略&quot;">​</a></h3><p>根据数据调整：</p><ul><li>如果上午被打断多 → 把重要任务移到下午</li><li>如果某类任务总被打断 → 拆分成更小的番茄</li><li>如果外部打断多 → 加强隔离措施</li></ul><hr><h2 id="中断的番茄怎么处理" tabindex="-1">中断的番茄怎么处理 <a class="header-anchor" href="#中断的番茄怎么处理" aria-label="Permalink to &quot;中断的番茄怎么处理&quot;">​</a></h2><p>如果一个番茄被紧急事务中断（无法推迟）：</p><ol><li><strong>立即停止计时</strong></li><li><strong>在任务追踪中标记为&quot;中断&quot;</strong></li><li><strong>记录中断原因</strong></li><li><strong>处理紧急事务</strong></li><li><strong>休息或直接开始新番茄</strong>（这个番茄作废，不算入统计）</li></ol><blockquote><p><strong>规则</strong>：被中断的番茄<strong>不算完成</strong>，不能休息。要么完成一个完整番茄，要么作废重新开始。</p></blockquote><hr><h2 id="本阶段检查清单" tabindex="-1">本阶段检查清单 <a class="header-anchor" href="#本阶段检查清单" aria-label="Permalink to &quot;本阶段检查清单&quot;">​</a></h2><ul><li>[ ] 每个番茄都记录打断次数和类型</li><li>[ ] 内部打断快速记下，不跟随</li><li>[ ] 外部打断尽量推迟到番茄结束</li><li>[ ] 每周回顾打断数据，寻找规律</li><li>[ ] 根据数据调整工作环境和时间安排</li></ul><hr><h2 id="什么时候进入下一阶段" tabindex="-1">什么时候进入下一阶段 <a class="header-anchor" href="#什么时候进入下一阶段" aria-label="Permalink to &quot;什么时候进入下一阶段&quot;">​</a></h2><p>当你：</p><ul><li>能区分内部和外部打断</li><li>形成了&quot;记录但不跟随&quot;的习惯</li><li>打断次数明显减少或至少被记录</li></ul><p>进入 <a href="./03-estimate-tasks.html">03-estimate-tasks.md</a>，学习如何提高预估准确度。</p>',30))])}const b=r(A,[["render",B]]);export{f as __pageData,b as default};
